import { Test, TestingModule } from '@nestjs/testing';
import { INestApplication, ValidationPipe } from '@nestjs/common';
import supertest from 'supertest';
import { AppModule } from '../src/app.module';
import { PrismaService } from '../src/prisma/prisma.service';

type SuperTestRequest = ReturnType<typeof supertest>;

/**
 * AI Chatbot & Planner Integration Tests
 * 
 * Comprehensive integration test suite covering:
 * - POSITIVE: Full flow Chat → Planner → Accept Plan
 * - NEGATIVE: Invalid input, failures
 * - CONCURRENCY: Multiple parallel requests
 */

// Mock data
const testUser = {
  id: 1,
  email: 'test@example.com',
  role: 'CUSTOMER' as const,
};

const mockAIPlan = {
  id: 1,
  userId: 1,
  budget: 500000,
  city: 'Mumbai',
  area: 'Bandra',
  guestCount: 300,
  eventType: 'Wedding',
  planJson: {
    summary: {
      eventType: 'Wedding',
      city: 'Mumbai',
      guestCount: 300,
      totalBudget: 500000,
    },
    allocations: [
      { category: 'Venue', amount: 150000, notes: 'Grand ballroom' },
      { category: 'Catering', amount: 200000, notes: 'Per plate' },
      { category: 'Decor', amount: 100000, notes: 'Flowers' },
      { category: 'Photography', amount: 50000, notes: 'Full day' },
    ],
  },
  status: 'GENERATED',
  shareId: 'test-share-123',
  isPublic: false,
  createdAt: new Date(),
  updatedAt: new Date(),
};

describe('AI Chatbot & Planner Integration Tests', () => {
  let app: INestApplication;
  let prisma: PrismaService;
  let request: SuperTestRequest;

  // Mock JWT token
  const mockJwtToken = 'mock-jwt-token';

  // Mock services
  const mockPrisma = {
    $transaction: jest.fn((callback) => callback({
      aIConversation: {
        create: jest.fn(),
        findFirst: jest.fn(),
        findUnique: jest.fn(),
        update: jest.fn(),
      },
      aIPlan: {
        create: jest.fn(),
        findFirst: jest.fn(),
        findUnique: jest.fn(),
        update: jest.fn(),
      },
      vendorService: {
        findMany: jest.fn(),
      },
      cart: {
        create: jest.fn(),
        findFirst: jest.fn(),
      },
    })),
    aIConversation: {
      create: jest.fn(),
      findFirst: jest.fn(),
      findUnique: jest.fn(),
      update: jest.fn(),
      deleteMany: jest.fn(),
    },
    aIPlan: {
      create: jest.fn(),
      findFirst: jest.fn(),
      findUnique: jest.fn(),
      update: jest.fn(),
    },
    vendorService: {
      findMany: jest.fn(),
    },
    cart: {
      create: jest.fn(),
      findFirst: jest.fn(),
    },
  };

  const mockOpenAIProvider = {
    generate: jest.fn(),
    isAvailable: jest.fn().mockReturnValue(true),
    generateWithCircuitBreaker: jest.fn(),
  };

  const mockAIPlannerQueue = {
    addGeneratePlanJob: jest.fn().mockResolvedValue({ jobId: 'job-123' }),
    getJobStatus: jest.fn(),
    isHealthy: jest.fn().mockResolvedValue(true),
    getQueueStats: jest.fn().mockResolvedValue({
      waiting: 0,
      active: 0,
      completed: 1,
      failed: 0,
    }),
  };

  beforeAll(async () => {
    const moduleFixture: TestingModule = await Test.createTestingModule({
      imports: [AppModule],
    })
      .overrideProvider(PrismaService)
      .useValue(mockPrisma)
      .compile();

    app = moduleFixture.createNestApplication();
    app.useGlobalPipes(new ValidationPipe({ transform: true, whitelist: true }));
    await app.init();

    prisma = app.get<PrismaService>(PrismaService);
    request = supertest(app.getHttpServer());
  });

  afterAll(async () => {
    await app.close();
  });

  beforeEach(() => {
    jest.clearAllMocks();
  });

  // ============================================
  // HELPER FUNCTIONS
  // ============================================

  const createMockConversation = (overrides = {}) => ({
    id: 'conv-' + Math.random().toString(36).substr(2, 9),
    userId: testUser.id,
    state: {},
    status: 'COLLECTING',
    planId: null,
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  });

  const createMockPlan = (overrides = {}) => ({
    ...mockAIPlan,
    ...overrides,
  });

  // ============================================
  // PUBLIC ENDPOINTS (No Auth Required)
  // ============================================

  describe('GET /ai-chat/public/demo', () => {
    /**
     * Test: should return demo response
     * Validates public demo endpoint
     */
    it('should return demo response', async () => {
      const response = await request
        .get('/ai-chat/public/demo')
        .expect(200);

      expect(response.body).toBeDefined();
      expect(response.body.isDemo).toBe(true);
      expect(response.body.conversationId).toBe('demo-conversation-id');
    });
  });

  // ============================================
  // CHAT ENDPOINTS (Authenticated)
  // ============================================

  describe('POST /ai-chat/message (Authenticated)', () => {
    /**
     * Test: should create new conversation for valid message
     * Validates positive flow
     */
    it('should create new conversation for valid message', async () => {
      // Arrange
      const newConversation = createMockConversation();
      mockPrisma.aIConversation.create.mockResolvedValue(newConversation);
      mockPrisma.aIConversation.findFirst.mockResolvedValue(null);
      mockOpenAIProvider.generate
        .mockResolvedValueOnce(JSON.stringify({
          intent: 'COLLECT_INFO',
          confidence: 0.9,
        }))
        .mockResolvedValueOnce('Great! I can help you plan your wedding.');

      const response = await request
        .post('/ai-chat/message')
        .set('Authorization', `Bearer ${mockJwtToken}`)
        .send({
          message: 'I want to plan a wedding',
        })
        .expect(200);

      expect(response.body).toBeDefined();
      expect(response.body.conversationId).toBeDefined();
      expect(response.body.reply).toBeDefined();
    });

    /**
     * Test: should return 400 for empty message
     * Validates input validation
     */
    it('should return 400 for empty message', async () => {
      const response = await request
        .post('/ai-chat/message')
        .set('Authorization', `Bearer ${mockJwtToken}`)
        .send({
          message: '',
        })
        .expect(400);

      expect(response.body.message).toContain('Message cannot be empty');
    });

    /**
     * Test: should return 400 for whitespace-only message
     * Validates input sanitization
     */
    it('should return 400 for whitespace-only message', async () => {
      const response = await request
        .post('/ai-chat/message')
        .set('Authorization', `Bearer ${mockJwtToken}`)
        .send({
          message: '   ',
        })
        .expect(400);

      expect(response.body.message).toContain('Message cannot be empty');
    });
  });

  describe('POST /ai-chat/public/message (Guest)', () => {
    /**
     * Test: should handle guest message
     * Validates guest user flow
     */
    it('should handle guest message', async () => {
      // Arrange
      mockOpenAIProvider.generate
        .mockResolvedValueOnce(JSON.stringify({
          intent: 'COLLECT_INFO',
          confidence: 0.9,
        }))
        .mockResolvedValueOnce('Great! What city are you planning in?');

      const response = await request
        .post('/ai-chat/public/message')
        .send({
          message: 'I want to plan a wedding',
        })
        .expect(200);

      expect(response.body).toBeDefined();
      expect(response.body.requiresAuth).toBe(true);
    });

    /**
     * Test: should return 400 for empty guest message
     * Validates guest input validation
     */
    it('should return 400 for empty guest message', async () => {
      const response = await request
        .post('/ai-chat/public/message')
        .send({
          message: '',
        })
        .expect(400);
    });
  });

  // ============================================
  // PLANNER ENDPOINTS
  // ============================================

  describe('POST /ai-planner/generate', () => {
    /**
     * Test: should accept valid plan generation request
     * Validates async plan generation
     */
    it('should accept valid plan generation request', async () => {
      // Arrange
      mockAIPlannerQueue.addGeneratePlanJob.mockResolvedValue({ jobId: 'job-new-123' });

      const response = await request
        .post('/ai-planner/generate')
        .set('Authorization', `Bearer ${mockJwtToken}`)
        .send({
          budget: 500000,
          eventType: 'Wedding',
          city: 'Mumbai',
          guestCount: 300,
        })
        .expect(202);

      expect(response.body).toBeDefined();
      expect(response.body.jobId).toBeDefined();
      expect(response.body.message).toContain('queued');
    });

    /**
     * Test: should return 400 for missing required fields
     * Validates DTO validation
     */
    it('should return 400 for missing required fields', async () => {
      const response = await request
        .post('/ai-planner/generate')
        .set('Authorization', `Bearer ${mockJwtToken}`)
        .send({
          budget: 500000,
          // Missing eventType, city, guestCount
        })
        .expect(400);
    });

    /**
     * Test: should return 400 for invalid budget
     * Validates budget validation
     */
    it('should return 400 for invalid budget', async () => {
      const response = await request
        .post('/ai-planner/generate')
        .set('Authorization', `Bearer ${mockJwtToken}`)
        .send({
          budget: -1000,
          eventType: 'Wedding',
          city: 'Mumbai',
          guestCount: 300,
        })
        .expect(400);
    });

    /**
     * Test: should return 400 for invalid guest count
     * Validates guest count limits
     */
    it('should return 400 for invalid guest count', async () => {
      const response = await request
        .post('/ai-planner/generate')
        .set('Authorization', `Bearer ${mockJwtToken}`)
        .send({
          budget: 500000,
          eventType: 'Wedding',
          city: 'Mumbai',
          guestCount: 0,
        })
        .expect(400);
    });
  });

  describe('GET /ai-planner/jobs/:jobId', () => {
    /**
     * Test: should return job status
     * Validates job status retrieval
     */
    it('should return job status', async () => {
      // Arrange
      mockAIPlannerQueue.getJobStatus.mockResolvedValue({
        jobId: 'job-123',
        status: 'completed',
        progress: 100,
        attempts: 1,
        result: { planId: 1 },
      });

      const response = await request
        .get('/ai-planner/jobs/job-123')
        .expect(200);

      expect(response.body).toBeDefined();
      expect(response.body.jobId).toBe('job-123');
    });

    /**
     * Test: should return 400 for missing jobId
     * Validates parameter validation
     */
    it('should return 400 for missing jobId', async () => {
      const response = await request
        .get('/ai-planner/jobs/')
        .expect(404);
    });
  });

  describe('GET /ai-planner/health', () => {
    /**
     * Test: should return health status
     * Validates health check endpoint
     */
    it('should return health status', async () => {
      const response = await request
        .get('/ai-planner/health')
        .expect(200);

      expect(response.body).toBeDefined();
      expect(response.body.redis).toBeDefined();
      expect(response.body.queue).toBeDefined();
    });
  });

  describe('GET /ai-planner/public/plan/:shareId', () => {
    /**
     * Test: should return public plan
     * Validates public plan sharing
     */
    it('should return public plan', async () => {
      // Arrange
      const publicPlan = createMockPlan({ isPublic: true });
      mockPrisma.aIPlan.findUnique.mockResolvedValue(publicPlan);

      const response = await request
        .get('/ai-planner/public/plan/test-share-123')
        .expect(200);

      expect(response.body).toBeDefined();
      expect(response.body.id).toBeDefined();
    });

    /**
     * Test: should return 404 for non-public plan
     * Validates privacy check
     */
    it('should return 404 for non-public plan', async () => {
      // Arrange
      const privatePlan = createMockPlan({ isPublic: false });
      mockPrisma.aIPlan.findUnique.mockResolvedValue(privatePlan);

      const response = await request
        .get('/ai-planner/public/plan/test-share-123')
        .expect(404);
    });

    /**
     * Test: should return 404 for non-existent plan
     * Validates missing plan handling
     */
    it('should return 404 for non-existent plan', async () => {
      // Arrange
      mockPrisma.aIPlan.findUnique.mockResolvedValue(null);

      const response = await request
        .get('/ai-planner/public/plan/non-existent')
        .expect(404);
    });
  });

  describe('POST /ai-planner/:id/vendors', () => {
    /**
     * Test: should match vendors from plan
     * Validates vendor matching
     */
    it('should match vendors from plan', async () => {
      // Arrange
      const plan = createMockPlan();
      const vendors = [
        { id: 1, name: 'Test Catering', baseRate: 50000, isActive: true },
      ];
      mockPrisma.aIPlan.findFirst.mockResolvedValue(plan);
      mockPrisma.vendorService.findMany.mockResolvedValue(vendors);

      const response = await request
        .post('/ai-planner/1/vendors')
        .set('Authorization', `Bearer ${mockJwtToken}`)
        .expect(201);

      expect(response.body).toBeDefined();
    });

    /**
     * Test: should return 400 for non-existent plan
     * Validates error handling
     */
    it('should return 400 for non-existent plan', async () => {
      // Arrange
      mockPrisma.aIPlan.findFirst.mockResolvedValue(null);

      const response = await request
        .post('/ai-planner/999/vendors')
        .set('Authorization', `Bearer ${mockJwtToken}`)
        .expect(400);
    });
  });

  describe('POST /ai-planner/:id/accept', () => {
    /**
     * Test: should accept plan and create cart
     * Validates plan acceptance flow
     */
    it('should accept plan and create cart', async () => {
      // Arrange
      const plan = createMockPlan();
      const mockCart = {
        id: 1,
        userId: testUser.id,
        status: 'ACTIVE',
        items: [],
      };
      mockPrisma.aIPlan.findFirst.mockResolvedValue(plan);
      mockPrisma.cart.create.mockResolvedValue(mockCart);
      mockPrisma.aIPlan.update.mockResolvedValue({ ...plan, status: 'ACCEPTED' });

      const response = await request
        .post('/ai-planner/1/accept')
        .set('Authorization', `Bearer ${mockJwtToken}`)
        .expect(201);

      expect(response.body).toBeDefined();
      expect(response.body.id).toBe(1);
    });

    /**
     * Test: should return 400 for non-existent plan
     * Validates error handling
     */
    it('should return 400 for non-existent plan', async () => {
      // Arrange
      mockPrisma.aIPlan.findFirst.mockResolvedValue(null);

      const response = await request
        .post('/ai-planner/999/accept')
        .set('Authorization', `Bearer ${mockJwtToken}`)
        .expect(400);
    });
  });

  // ============================================
  // CONCURRENCY TESTS
  // ============================================

  describe('Concurrency Tests', () => {
    /**
     * Test: should handle 10 parallel planner requests
     * Validates queue handling under load
     */
    it('should handle 10 parallel planner requests', async () => {
      // Arrange
      const requests = Array.from({ length: 10 }, (_, i) => ({
        budget: 500000 + i * 10000,
        eventType: 'Wedding',
        city: 'Mumbai',
        guestCount: 300,
      }));

      // Act & Assert - all should succeed or fail gracefully
      const promises = requests.map((data) =>
        request
          .post('/ai-planner/generate')
          .set('Authorization', `Bearer ${mockJwtToken}`)
          .send(data)
          .then((res) => ({ status: res.status, body: res.body })),
      );

      const results = await Promise.all(promises);

      // Verify no crashes
      results.forEach((result) => {
        expect([202, 400, 401, 429]).toContain(result.status);
      });
    });

    /**
     * Test: should handle multiple chat messages concurrently
     * Validates chat service under load
     */
    it('should handle multiple chat messages concurrently', async () => {
      // Arrange
      const messages = [
        'I want to plan a wedding',
        'For 200 guests',
        'In Bangalore',
        'With 5 lakh budget',
      ];

      // Act & Assert
      const promises = messages.map((message) =>
        request
          .post('/ai-chat/public/message')
          .send({ message })
          .then((res) => ({ status: res.status, body: res.body })),
      );

      const results = await Promise.all(promises);

      // All should complete without crashing
      results.forEach((result) => {
        expect([200, 400]).toContain(result.status);
      });
    });
  });

  // ============================================
  // FULL FLOW TESTS
  // ============================================

  describe('Full Flow: Chat → Planner → Accept Plan', () => {
    /**
     * Test: should complete full flow from chat to plan acceptance
     * Validates complete user journey
     */
    it('should complete full flow from chat to plan acceptance', async () => {
      // Step 1: Create conversation via chat
      const conversation = createMockConversation();
      mockPrisma.aIConversation.create.mockResolvedValue(conversation);
      mockPrisma.aIConversation.findFirst.mockResolvedValue(null);
      mockOpenAIProvider.generate
        .mockResolvedValueOnce(JSON.stringify({
          intent: 'COLLECT_INFO',
          confidence: 0.9,
          budget: 500000,
          guestCount: 300,
          city: 'Mumbai',
          eventType: 'Wedding',
        }))
        .mockResolvedValueOnce('Your plan is being generated!');

      const chatResponse = await request
        .post('/ai-chat/message')
        .set('Authorization', `Bearer ${mockJwtToken}`)
        .send({
          message: 'Wedding in Mumbai for 300 guests with 5 lakh budget',
        });

      expect(chatResponse.status).toBe(200);

      // Step 2: Generate plan
      mockAIPlannerQueue.addGeneratePlanJob.mockResolvedValue({ jobId: 'job-flow-123' });

      const planResponse = await request
        .post('/ai-planner/generate')
        .set('Authorization', `Bearer ${mockJwtToken}`)
        .send({
          conversationId: chatResponse.body.conversationId,
          budget: 500000,
          eventType: 'Wedding',
          city: 'Mumbai',
          guestCount: 300,
        });

      expect(planResponse.status).toBe(202);

      // Step 3: Check job status
      mockAIPlannerQueue.getJobStatus.mockResolvedValue({
        jobId: 'job-flow-123',
        status: 'completed',
        progress: 100,
        result: { planId: 1 },
      });

      const statusResponse = await request
        .get('/ai-planner/jobs/job-flow-123');

      expect(statusResponse.status).toBe(200);

      // Step 4: Accept plan and create cart
      const plan = createMockPlan();
      const mockCart = { id: 1, userId: testUser.id, status: 'ACTIVE', items: [] };
      mockPrisma.aIPlan.findFirst.mockResolvedValue(plan);
      mockPrisma.cart.create.mockResolvedValue(mockCart);
      mockPrisma.aIPlan.update.mockResolvedValue({ ...plan, status: 'ACCEPTED' });

      const acceptResponse = await request
        .post('/ai-planner/1/accept')
        .set('Authorization', `Bearer ${mockJwtToken}`);

      expect(acceptResponse.status).toBe(201);
    });
  });
});
